export function filterWorkflows(searchQuery = '', filter = 'all') {
  const workflows = workflowsData.data || [];
  return workflows.filter(wf => {
    if (filter === 'active' && !wf.active) return false;
    if (filter === 'inactive' && wf.active) return false;
    if (searchQuery) {
      const name = wf.name.toLowerCase();
      const id = wf.id.toLowerCase();
      const tags = (wf.tags || []).map(t => t.name.toLowerCase()).join(' ');
      return name.includes(searchQuery) || id.includes(searchQuery) || tags.includes(searchQuery);
    }
    return true;
  });
}

export function getWorkflows() {
  return workflowsData.data || [];
}
